window.VBPAppUnsplash={showUnsplashModal:!1,unsplashConfigured:!0,unsplashQuery:"",unsplashOrientation:"",unsplashImages:[],unsplashPage:1,unsplashTotalPages:0,isSearchingUnsplash:!1,unsplashTargetElement:null,openUnsplash:function(s){this.unsplashTargetElement=s||null,this.showUnsplashModal=!0,this.checkUnsplashStatus()},checkUnsplashStatus:function(){var s=this;fetch(VBP_Config.restUrl+"unsplash/status",{method:"GET",headers:{"X-WP-Nonce":VBP_Config.restNonce}}).then((function(s){return s.json()})).then((function(n){s.unsplashConfigured=n.configured||!1})).catch((function(){s.unsplashConfigured=!1}))},searchUnsplash:function(){if(this.unsplashQuery.trim()){var s=this;this.isSearchingUnsplash=!0,this.unsplashPage=1;var n=VBP_Config.restUrl+"unsplash/search?"+new URLSearchParams({query:this.unsplashQuery,page:this.unsplashPage,per_page:20,orientation:this.unsplashOrientation});fetch(n,{method:"GET",headers:{"X-WP-Nonce":VBP_Config.restNonce}}).then((function(s){return s.json()})).then((function(n){if(n.error)throw new Error(n.error);s.unsplashImages=n.results||[],s.unsplashTotalPages=n.totalPages||0})).catch((function(n){s.showNotification("Error buscando imágenes: "+n.message,"error"),s.unsplashImages=[]})).finally((function(){s.isSearchingUnsplash=!1}))}},unsplashNextPage:function(){this.unsplashPage>=this.unsplashTotalPages||(this.unsplashPage++,this.loadUnsplashPage())},unsplashPrevPage:function(){this.unsplashPage<=1||(this.unsplashPage--,this.loadUnsplashPage())},loadUnsplashPage:function(){var s=this;this.isSearchingUnsplash=!0;var n=VBP_Config.restUrl+"unsplash/search?"+new URLSearchParams({query:this.unsplashQuery,page:this.unsplashPage,per_page:20,orientation:this.unsplashOrientation});fetch(n,{method:"GET",headers:{"X-WP-Nonce":VBP_Config.restNonce}}).then((function(s){return s.json()})).then((function(n){s.unsplashImages=n.results||[]})).catch((function(){s.showNotification("Error cargando página","error")})).finally((function(){s.isSearchingUnsplash=!1}))},selectUnsplashImage:function(s){if(fetch(VBP_Config.restUrl+"unsplash/photos/"+s.id+"/download",{method:"POST",headers:{"X-WP-Nonce":VBP_Config.restNonce}}).catch((function(){return null})),this.unsplashTargetElement){var n=Alpine.store("vbp"),a=n.getElement(this.unsplashTargetElement);if(a){var e=JSON.parse(JSON.stringify(a.data||{}));e.src=s.urls.regular,e.alt=s.description||"Imagen de "+s.user.name+" en Unsplash",e.unsplashId=s.id,e.unsplashAuthor=s.user.name,e.unsplashAuthorUrl=s.user.link,n.updateElement(this.unsplashTargetElement,{data:e}),this.showNotification("Imagen actualizada","success")}}else{Alpine.store("vbp").addElement("image",{src:s.urls.regular,alt:s.description||"Imagen de "+s.user.name+" en Unsplash",unsplashId:s.id,unsplashAuthor:s.user.name,unsplashAuthorUrl:s.user.link}),this.showNotification("Imagen insertada","success")}this.showUnsplashModal=!1,this.unsplashTargetElement=null}};